const config = $('Configuration').first().json;
const count = config.slotCount;
const prefix = config.namingPrefix;
const padLen = Math.max(3, String(count).length);

const items = [];
for (let i = 1; i <= count; i++) {
  const num = String(i).padStart(padLen, '0');
  items.push({
    json: {
      slotName: `${prefix}${num}`,
      requestBody: {
        name: `${prefix}${num}`,
        nodes: [{
          id: "trigger",
          name: "When clicking 'Test workflow'",
          type: "n8n-nodes-base.manualTrigger",
          typeVersion: 1,
          position: [0, 0],
          parameters: {}
        }],
        connections: {},
        settings: { executionOrder: "v1" }
      }
    }
  });
}

return items;

const items = $input.all();
const created = items.map(item => ({
  id: item.json.id,
  name: item.json.name
}));

return [{
  json: {
    totalCreated: created.length,
    workflows: created,
    message: `Created ${created.length} empty workflow slots ready for SDLC reserve-and-claim.`
  }
}];
